# Unit Tests for `memoize` Decorator

```python
import pytest
from unittest.mock import MagicMock


# Assuming the memoize function is importable; otherwise paste it here
def memoize(fn):
    cache = {}
    def wrapper(*args):
        if args not in cache:
            cache[args] = fn(*args)
        return cache[args]
    return wrapper


# ---------------------------------------------------------------------------
# Happy Path Tests
# ---------------------------------------------------------------------------

class TestMemoizeHappyPath:
    def test_returns_correct_result_single_arg(self):
        @memoize
        def square(x):
            return x * x

        assert square(3) == 9
        assert square(4) == 16

    def test_returns_correct_result_multiple_args(self):
        @memoize
        def add(a, b):
            return a + b

        assert add(2, 3) == 5
        assert add(10, 20) == 30

    def test_caches_result_function_called_once(self):
        mock_fn = MagicMock(return_value=42)
        memoized = memoize(mock_fn)

        memoized(1, 2)
        memoized(1, 2)
        memoized(1, 2)

        mock_fn.assert_called_once_with(1, 2)

    def test_different_args_call_function_again(self):
        mock_fn = MagicMock(side_effect=lambda x: x * 2)
        memoized = memoize(mock_fn)

        memoized(1)
        memoized(2)
        memoized(3)

        assert mock_fn.call_count == 3

    def test_cached_value_returned_on_repeat_call(self):
        call_count = {"n": 0}

        @memoize
        def slow(x):
            call_count["n"] += 1
            return x + 100

        assert slow(5) == 105
        assert slow(5) == 105
        assert call_count["n"] == 1

    def test_zero_argument_function(self):
        mock_fn = MagicMock(return_value="hello")
        memoized = memoize(mock_fn)

        assert memoized() == "hello"
        assert memoized() == "hello"
        mock_fn.assert_called_once()


