class TestMemoizeEdgeCases:
    def test_returns_none_when_function_returns_none(self):
        mock_fn = MagicMock(return_value=None)
        memoized = memoize(mock_fn)

        assert memoized(1) is None
        assert memoized(1) is None
        # Important: even though None is returned, it should still be cached
        mock_fn.assert_called_once()

    def test_distinguishes_int_and_float_keys_correctly(self):
        # In Python, hash(1) == hash(1.0), and 1 == 1.0, so they share cache
        mock_fn = MagicMock(side_effect=lambda x: type(x).__name__)
        memoized = memoize(mock_fn)

        result1 = memoized(1)
        result2 = memoized(1.0)

        # Cache treats 1 and 1.0 as the same key (dict equality)
        assert result1 == result2 == "int"
        mock_fn.assert_called_once()

    def test_handles_string_arguments(self):
        @memoize
        def upper(s):
            return s.upper()

        assert upper("hello") == "HELLO"
        assert upper("hello") == "HELLO"
        assert upper("world") == "WORLD"

    def test_handles_tuple_arguments(self):
        @memoize
        def sum_tuple(t):
            return sum(t)

        assert sum_tuple((1, 2, 3)) == 6
        assert sum_tuple((1, 2, 3)) == 6

    def test_independent_cache_per_decoration(self):
        @memoize
        def fn_a(x):
            return x + 1

        @memoize
        def fn_b(x):
            return x + 2

        assert fn_a(1) == 2
        assert fn_b(1) == 3

    def test_preserves_falsy_return_values(self):
        @memoize
        def returns_falsy(x):
            return x

        assert returns_falsy(0) == 0
        assert returns_falsy("") == ""
        assert returns_falsy(False) is False
        assert returns_falsy([]) == []

    def test_large_number_of_distinct_calls(self):
        @memoize
        def identity(x):
            return x

        for i in range(1000):
            assert identity(i) == i
        # Repeat — should all be cached
        for i in range(1000):
            assert identity(i) == i

    def test_recursive_function_memoization(self):
        @memoize
        def fib(n):
            if n < 2:
                return n
            return fib(n - 1) + fib(n - 2)

        assert fib(10) == 55
        assert fib(20) == 6765

    def test_negative_and_zero_arguments(self):
        @memoize
        def negate(x):
            return -x

        assert negate(0) == 0
        assert negate(-5) == 5
        assert negate(5) == -5


